/**
 * Database migration runner for Composer
 *
 * Uses drizzle-orm's migrate function to apply SQL migrations
 * from the migrations folder generated by drizzle-kit.
 */

import { existsSync, readFileSync, readdirSync } from "node:fs";
import { dirname, join, resolve } from "node:path";
import { fileURLToPath } from "node:url";
import { sql } from "drizzle-orm";
import { createLogger } from "../utils/logger.js";
import { getDb, isDatabaseConfigured } from "./client.js";

const logger = createLogger("db:migrate");

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);
const MIGRATIONS_DIR = join(__dirname, "migrations");

interface MigrationJournal {
	version: string;
	dialect: string;
	entries: Array<{
		idx: number;
		version: string;
		when: number;
		tag: string;
		breakpoints: boolean;
	}>;
}

interface MigrationRecord {
	tag: string;
	applied_at: Date;
}

export interface InitialSchemaMarker {
	kind: "constraint" | "index" | "table" | "type";
	name: string;
	exists: boolean;
}

export interface InitialSchemaState {
	exists: boolean;
	partial: boolean;
	present: string[];
	missing: string[];
}

type InitialSchemaMarkerDefinition = Pick<InitialSchemaMarker, "kind" | "name">;

